import { create } from 'zustand'

export const useCountdownStore = create((set) => ({
    timeInput: {
        hours: '',
        minutes: '',
        seconds: ''
    },
    time: null,
    initialSeconds: 0,
    isRunning: false,
    setTimeInput: (input) => set((state) => ({
        timeInput: {
            ...state.timeInput,
            hours: input.hours,
            seconds: input.seconds,
            minutes: input.minutes
        },
        initialSeconds: (input.hours || 0) * 3600 + (input.minutes || 0) * 60 + (input.seconds || 0)
    })),
